sed -n '1,240p' model.py && sed -n '1,240p' train_lstm_val.py && python - <<'PY'
import torch, json, os
for f in ['checkpoints/best.pt','checkpoints/combined_best.pt','checkpoints/combined_7seed.pt','checkpoints/mix_gru90_lstm10.pt','checkpoints/lstm_val_ensemble.pt']:
    if os.path.exists(f):
        ck=torch.load(f,map_location='cpu')
        ms=ck.get('members')
        info={'file':f,'keys':list(ck.keys()),'members':len(ms) if ms else 1}
        if ms:
            info['member0_config']=ms[0].get('config')
            info['member_epochs']=[m.get('epoch',m.get('best_epoch')) for m in ms]
            info['weights']=[m.get('weight') for m in ms[:10]]
            info['sources']=[m.get('source') for m in ms[:10]]
        else:
            info['config']=ck.get('config')
        print(json.dumps(info, default=str))
